	once.Do(func() {
		cfg = &config{Env: "production"}
		fmt.Println("config loaded once")
	})
	return cfg
}

func main() {
	var wg sync.WaitGroup
	for i := 0; i < 8; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			_ = loadConfig()
		}()
	}
	wg.Wait()
	fmt.Println("env:", loadConfig().Env)
}
